class ChatPageHandler {
    constructor() {
        this.currentProposal = null;
        this.setupActionListeners();
    }

    setupActionListeners() {
        document.addEventListener('click', (e) => {
            const generateBtn = e.target.closest('[data-generate]');
            if (generateBtn) {
                const periodType = generateBtn.dataset.generate;
                this.handleGenerate(periodType);
            }

            const acceptBtn = e.target.closest('#acceptProposalBtn');
            if (acceptBtn && this.currentProposal) {
                this.handleAccept();
            }

            const declineBtn = e.target.closest('#declineProposalBtn');
            if (declineBtn && this.currentProposal) {
                this.handleDecline();
            }
        });
    }

    async init() {
        this.currentProposal = null;
        this.renderActionBar();
        this.loadChatHistory();
    }

    renderActionBar() {
        // The action bar is already in the template from index.html
    }

    async loadChatHistory() {
        const container = document.getElementById('chatMessages');
        try {
            const data = await api.getChatHistory();
            const messages = data.messages || [];
            container.innerHTML = messages.map(msg => this.renderMessage(msg)).join('');
            this.scrollToBottom();
        } catch (err) {
            container.innerHTML = '<div class="chat-message bot-message"><p>Failed to load chat history</p></div>';
        }
    }

    renderMessage(msg) {
        const isUser = msg.role === 'user';
        const time = msg.createdAt ? new Date(msg.createdAt).toLocaleTimeString() : '';
        return `
            <div class="chat-message ${isUser ? 'user-message' : 'bot-message'}">
                <p>${this.escapeHtml(msg.content)}</p>
                <span class="chat-timestamp">${time}</span>
            </div>
        `;
    }

    async handleChatSubmit(input) {
        const message = input.value.trim();
        if (!message) return;

        // Add user message to UI
        const container = document.getElementById('chatMessages');
        container.innerHTML += `
            <div class="chat-message user-message">
                <p>${this.escapeHtml(message)}</p>
                <span class="chat-timestamp">${new Date().toLocaleTimeString()}</span>
            </div>
        `;
        input.value = '';
        this.scrollToBottom();

        try {
            const response = await api.sendChatMessage(message);
            container.innerHTML += `
                <div class="chat-message bot-message">
                    <p>${this.escapeHtml(response.content || response.message || 'No response')}</p>
                    <span class="chat-timestamp">${new Date().toLocaleTimeString()}</span>
                </div>
            `;
            this.scrollToBottom();
        } catch (err) {
            router.setState({ error: err.message });
        }
    }

    async handleGenerate(periodType) {
        const container = document.getElementById('chatMessages');
        container.innerHTML += `
            <div class="chat-message user-message">
                <p>Generate ${periodType} plan</p>
                <span class="chat-timestamp">${new Date().toLocaleTimeString()}</span>
            </div>
