                </div>
            </div>
        `;
    }

    html += `
        <div class="proposal-actions">
            <button class="btn btn-primary proposal-accept" data-proposal-id="${plan.id}">Accept</button>
            <button class="btn btn-secondary proposal-decline" data-proposal-id="${plan.id}">Decline</button>
        </div>
    `;
    html += '</div>';
    return html;
}

