}

input.newString:
async handleChatSubmit(input) {
    const message = input.value.trim();
    if (!message) return;

    const container = document.getElementById('chatMessages');
    this.appendMessage(container, 'user', message);
    input.value = '';
    this.scrollToBottom();

    try {
        const response = await api.sendChatMessage(message);
        if (response.role === 'assistant') {
            this.appendMessage(container, 'bot', response.content || 'No response');
        } else {
            this.appendMessage(container, 'bot', 'Message received. Use the action buttons above to generate a plan, or ask me to help with your meal prep!');
        }
        this.scrollToBottom();
    } catch (err) {
        this.appendMessage(container, 'bot', 'Sorry, I encountered an error. Please try again.');
        this.scrollToBottom();
        router.setState({ error: err.message });
    }
}

